//! Spawner reputation — closing the oath loop with trust.
//!
//! The Ulysses lifecycle is swear -> bind -> prove -> enforce (see [`crate::oath`]
//! and [`crate::breach`]). This module is the stage AFTER enforcement: SCORE.
//! A breach is recorded against the agent that broke its oath, but every agent
//! gets a FRESH DID per spawn — so per-agent-DID trust carries no history and is
//! meaningless. Trust must attach to a STABLE identity, and the stable identity
//! is the SPAWNER: the UCAN holder DID that requested the spawn
//! ([`crate::ledger::Subagent::spawned_by`], carried into
//! [`crate::breach::BreachRecord::spawned_by`] at breach time).
//!
//! So trust is a pure function of a spawner DID's breach history. The score then
//! GATES future spawns: admission can deny or down-weight a low-trust spawner
//! (see `ops::spawn`). An identity that repeatedly spawns oath-breaching agents
//! loses the right to keep spawning.
//!
//! TRUST FUNCTION (kept simple + documented):
//!
//! ```text
//!   trust = clamp(1.0 - PENALTY_PER_BREACH * breach_count, 0.0 ..= 1.0)
//! ```
//!
//! with `PENALTY_PER_BREACH = 0.34`, so:
//!   - 0 breaches -> 1.0 (full trust; default behavior unchanged)
//!   - 1 breach   -> 0.66
//!   - 2 breaches -> 0.32
//!   - 3+ breaches -> 0.0 (no trust)
//!
//! `breach_count` is the spawner's recorded breaches; this keeps the model a
//! pure step function of history (a recency window can be layered on later
//! without changing the gate's shape).

use serde::Serialize;

use crate::breach::{self, BreachRecord};

/// Trust lost per recorded breach. Three breaches drives a spawner to 0.0.
pub const PENALTY_PER_BREACH: f64 = 0.34;

/// Count a spawner DID's breaches in a breach log. An empty `spawner` (the
/// serde default for breach records written before `spawned_by` existed, or an
/// unattributable breach) matches only an empty query — we never blame the
/// "unknown" spawner for an identified one's breaches.
fn breach_count_for(log: &[BreachRecord], spawner: &str) -> usize {
    log.iter().filter(|b| b.spawned_by == spawner).count()
}

/// The pure trust kernel: turn a breach count into a trust score in `0.0..=1.0`.
/// Separated out so it can be unit-tested without touching disk.
pub fn trust_from_count(breach_count: usize) -> f64 {
    (1.0 - PENALTY_PER_BREACH * breach_count as f64).clamp(0.0, 1.0)
}

/// Trust of a spawner DID computed against a given breach log (pure; no disk).
pub fn trust_of_in(log: &[BreachRecord], spawner: &str) -> f64 {
    trust_from_count(breach_count_for(log, spawner))
}

/// Trust of a spawner DID = a function of its recorded breach history in the
/// audit log at `$MONSTER_GUARD_HOME/breaches.json`. A spawner with no breaches
/// scores 1.0 (full trust); each breach subtracts [`PENALTY_PER_BREACH`], floored
/// at 0.0. Loads the breach log fresh (a missing/corrupt log reads as no history,
/// i.e. full trust — see [`crate::breach::load`]).
pub fn trust_of(spawner: &str) -> f64 {
    trust_of_in(&breach::load(), spawner)
}

/// One spawner's reputation row: its DID, its trust score, and the breach count
/// that produced it. Serialize so the `trust` CLI / MCP tool can emit JSON.
#[derive(Serialize, Clone, Debug, PartialEq)]
pub struct SpawnerTrust {
    pub did: String,
    pub trust: f64,
    pub breaches: usize,
}

/// Reputation over a given breach log (pure): one row per distinct spawner DID
/// that appears in the log, sorted ascending by trust (least-trusted first) so a
/// reader sees the worst offenders at the top, ties broken by DID for stable
/// output. Spawners with NO breaches do not appear here (they are trust 1.0 by
/// definition and there is nothing to list); this surfaces only identities that
/// have a reputation cost.
pub fn all_trust_in(log: &[BreachRecord]) -> Vec<SpawnerTrust> {
    // Distinct spawner DIDs, preserving nothing but identity (skip the empty
    // unattributable spawner — it is not a real identity to score).
    let mut dids: Vec<String> = Vec::new();
    for b in log {
        if !b.spawned_by.is_empty() && !dids.contains(&b.spawned_by) {
            dids.push(b.spawned_by.clone());
        }
    }
    let mut rows: Vec<SpawnerTrust> = dids
        .into_iter()
        .map(|did| {
            let breaches = breach_count_for(log, &did);
            SpawnerTrust {
                trust: trust_from_count(breaches),
                breaches,
                did,
            }
        })
        .collect();
    rows.sort_by(|a, b| {
        a.trust
            .partial_cmp(&b.trust)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.did.cmp(&b.did))
    });
    rows
}

/// Reputation over the on-disk breach log. See [`all_trust_in`].
pub fn all_trust() -> Vec<SpawnerTrust> {
    all_trust_in(&breach::load())
}

#[cfg(test)]
mod tests {
    use super::*;

    fn rec(spawned_by: &str) -> BreachRecord {
        BreachRecord {
            id: "x".into(),
            name: "agent-x".into(),
            oath_sworn_by: None,
            oath: None,
            caste: "scout".into(),
            reason: "conduct: test".into(),
            reported_by: "did:key:zReporter".into(),
            verified: false,
            spawned_by: spawned_by.into(),
            ts: 0,
        }
    }

    #[test]
    fn clean_spawner_is_fully_trusted() {
        // No breaches in the log -> trust 1.0 (default behavior unchanged).
        let log: Vec<BreachRecord> = vec![];
        assert_eq!(trust_of_in(&log, "did:key:zClean"), 1.0);
        // And a spawner not present in a non-empty log is also fully trusted.
        let log = vec![rec("did:key:zOther")];
        assert_eq!(trust_of_in(&log, "did:key:zClean"), 1.0);
    }

    #[test]
    fn trust_drops_with_each_breach() {
        let s = "did:key:zRepeat";
        let one = vec![rec(s)];
        let two = vec![rec(s), rec(s)];
        let three = vec![rec(s), rec(s), rec(s)];
        let four = vec![rec(s), rec(s), rec(s), rec(s)];

        // Monotone descent, then floored at 0.0.
        assert!((trust_of_in(&one, s) - 0.66).abs() < 1e-9, "1 breach -> ~0.66");
        assert!((trust_of_in(&two, s) - 0.32).abs() < 1e-9, "2 breaches -> ~0.32");
        assert_eq!(trust_of_in(&three, s), 0.0, "3 breaches -> floored at 0.0");
        assert_eq!(trust_of_in(&four, s), 0.0, "stays floored, never negative");

        // Strictly decreasing while above the floor.
        assert!(trust_of_in(&one, s) > trust_of_in(&two, s));
        assert!(trust_of_in(&two, s) > trust_of_in(&three, s));
    }

    #[test]
    fn trust_is_per_spawner_not_global() {
        // Two spawners; one breaches twice, the other once. Each is scored only
        // on its OWN history (the point: trust attaches to the stable spawner).
        let log = vec![
            rec("did:key:zA"),
            rec("did:key:zA"),
            rec("did:key:zB"),
        ];
        assert!((trust_of_in(&log, "did:key:zA") - 0.32).abs() < 1e-9);
        assert!((trust_of_in(&log, "did:key:zB") - 0.66).abs() < 1e-9);
        assert_eq!(trust_of_in(&log, "did:key:zUnseen"), 1.0);
    }

    #[test]
    fn all_trust_lists_offenders_least_trusted_first() {
        let log = vec![
            rec("did:key:zA"),
            rec("did:key:zA"),
            rec("did:key:zA"), // A: 3 breaches -> 0.0
            rec("did:key:zB"), // B: 1 breach  -> 0.66
        ];
        let rows = all_trust_in(&log);
        assert_eq!(rows.len(), 2, "one row per distinct spawner DID");
        assert_eq!(rows[0].did, "did:key:zA", "least-trusted first");
        assert_eq!(rows[0].breaches, 3);
        assert_eq!(rows[0].trust, 0.0);
        assert_eq!(rows[1].did, "did:key:zB");
        assert_eq!(rows[1].breaches, 1);
        assert!((rows[1].trust - 0.66).abs() < 1e-9);
    }

    #[test]
    fn all_trust_skips_empty_spawner_and_dedups() {
        // The unattributable (empty) spawner is not a real identity to score, and
        // each DID appears exactly once even with repeated breaches.
        let log = vec![
            rec(""),          // unattributable: skipped
            rec("did:key:zA"),
            rec("did:key:zA"),
        ];
        let rows = all_trust_in(&log);
        assert_eq!(rows.len(), 1);
        assert_eq!(rows[0].did, "did:key:zA");
        assert_eq!(rows[0].breaches, 2);
    }
}
